[DataContract]
class ETGDMSSalesAgreementConfirmationContract extends BusinessEventsContract
{
    str                 SalesNumberSequence;
    str                 CustAccount;
    str                 documentTitle;
    str                 currency;
    str                 agreementClassification;
    AgreementState      agreementState;
    str                 dmsDealNumber;
    str                 message;


}

Method.Source:
[DataMemberAttribute('SalesNumberSequence')]
public str parmSalesNumberSequence(str _salesNumberSequence = SalesNumberSequence)
{
    SalesNumberSequence = _salesNumberSequence;
    return SalesNumberSequence;
}

[DataMemberAttribute('AgreementState')]
public AgreementState parmAgreementState(AgreementState _agreementState = agreementState)
{
    agreementState = _agreementState;
    return agreementState;
}

[DataMemberAttribute('CustAccount')]
public str parmCustAccount(str _custAccount = CustAccount)
{
    CustAccount = _custAccount;
    return CustAccount;
}

[DataMemberAttribute('DocumentTitle')]
public str parmDocumentTitle(str _documentTitle = documentTitle)
{
    documentTitle = _documentTitle;
    return documentTitle;
}

[DataMemberAttribute('Currency')]
public str parmCurrency(str _currency = currency)
{
    currency = _currency;
    return currency;
}

[DataMemberAttribute('AgreementClassification')]
public str parmAgreementClassification(str  _agreementClassification = agreementClassification)
{
    agreementClassification = _agreementClassification;
    return agreementClassification;
}

[DataMemberAttribute('DMSDealNumber')]
public str parmDMSDealNumber(str _dmsDealNumber = dmsDealNumber)
