}

private void initialize(SalesAgreementHeader _salesAgreementHeader, AgreementHeader _agreementHeader)
{
    SalesNumberSequence     = _salesAgreementHeader.SalesNumberSequence;
    CustAccount             = _salesAgreementHeader.CustAccount;;
    agreementState          = _agreementHeader.AgreementState;
    documentTitle           = _agreementHeader.DocumentTitle;
    currency                = _agreementHeader.Currency;
    agreementClassification = any2Str(_agreementHeader.AgreementClassification);
    str         custname    = _salesAgreementHeader.custName();
    dmsDealNumber           = _salesAgreementHeader.ETGDMSDealNumber;
   message                  ="Deal " + SalesNumberSequence + " has been confirmed";

}

public static ETGDMSSalesAgreementConfirmationContract newFromsalesAgreement(SalesAgreementHeader _salesAgreementHeader, AgreementHeader _agreementHeader)
{
    ETGDMSSalesAgreementConfirmationContract contract = new ETGDMSSalesAgreementConfirmationContract();
    contract.initialize(_salesAgreementHeader, _agreementHeader);
    return contract;
}
